mapper.select:
SELECT , m.ref_key, m.ref_type, m.sort_index FROM common_file file INNER JOIN common_file_map m ON file.file_key = m.file_key WHERE m.ref_key = #{refKey}
AND m.ref_type = #{refType}
ORDER BY m.sort_index ASC, file.reg_date DESC

mapper.delete:
DELETE FROM common_file_map
WHERE ref_key = #{refKey}

    AND ref_type = #{refType}


    AND file_key = #{fileKey}

mapper.select:
SELECT MAX(m.sort_index)
FROM common_file_map m
WHERE m.ref_key = #{refKey}
